  "TPR57_1_07": ["O que vem a seguir? Gato, Cachorro, Gato, Cachorro, Gato, ?", "Dois animais se alternam.", ["Gato", "Cachorro", "Pássaro", "Peixe"], "Gato e cachorro se alternam. Depois do Gato vem o Cachorro."],
  "TPR57_1_08": ["O que vem a seguir? Sol, Lua, Sol, Lua, Sol, ?", "Pense no dia e na noite. Mudar!", ["Estrela", "Nuvem", "Lua", "Sol"], "Sol e Lua se alternam. Depois do Sol vem a Lua."],
  "TPR57_1_09": ["O que vem a seguir? Círculo, Quadrado, Círculo, Quadrado, Círculo, ?", "Duas formas se alternam.", ["Triângulo", "Círculo", "Retângulo", "Quadrado"], "Círculo e Quadrado se alternam. Depois do Círculo vem o Quadrado."],
  "TPR57_1_10": ["O que vem a seguir? Dia, noite, dia, noite, dia, ?", "O dia e a noite se alternam!", ["Manhã", "Dia", "Tarde", "Noite"], "Dia e noite se alternam. Depois do dia vem a noite."],
  "TPR57_1_11": ["O que vem a seguir? Quente, frio, quente, frio, quente, ?", "Um está quente, o outro está frio. Eles se alternam.", ["Morno", "Frio", "Quente", "Gelado"], "Quente e frio se alternam. Depois de quente vem frio."],
  "TPR57_1_12": ["O que vem a seguir? Maçã, Banana, Maçã, Banana, Maçã, ?", "Duas frutas continuam mudando uma à outra!", ["Cereja", "maçã", "Banana", "Uva"], "Maçã e Banana se alternam. Depois da Maçã vem a Banana."],
  "TPR57_1_13": ["Quantos pontos vêm a seguir? 1 ponto, 2 pontos, 3 pontos, ?", "Conte os pontos. O número aumenta um a cada vez!", ["5 pontos", "2 pontos", "4 pontos", "1 ponto"], "Os pontos aumentam um a cada vez: 1, 2, 3 e depois 4 pontos."],
  "TPR57_1_14": ["Quantas palmas estão chegando? 1 batida, 2 batidas, 3 batidas, 4 batidas, ?", "O número de palmas está sempre aumentando. Qual número vem depois do 4?", ["5 batidas", "3 batidas", "6 batidas", "4 batidas"], "As palmas aumentam uma unidade de cada vez: 1, 2, 3, 4 e depois 5 palmas."],
  "TPR57_1_15": ["O que vem a seguir? Menino, menina, menino, menina, menino, ?", "Um menino e uma menina se alternam.", ["Garoto", "Garota", "bebê", "Homem"], "Menino e menina se alternam. Depois do Menino vem a Menina."],
  "TPR57_1_16": ["O que vem a seguir? Aberto, fechado, aberto, fechado, aberto, ?", "Abrimos e depois fechamos. Abrimos e depois fechamos. O que vem a seguir?", ["Trancado", "Aberto", "Batido", "Fechado"], "Aberto e fechado se alternam. Depois de aberto vem fechado."],
  "TPR57_1_17": ["O que vem a seguir? Esquerda, direita, esquerda, direita, esquerda, ?", "Esquerda e direita se alternam!", ["Direita", "Esquerda", "Para cima", "Para baixo"], "Esquerda e direita se alternam. Depois da esquerda vem a direita."],
  "TPR57_1_18": ["Quantas estrelas vêm a seguir? 1 estrela, 2 estrelas, 3 estrelas, 4 estrelas, ?", "Conte as estrelas. Eu cresço um a cada vez!", ["3 estrelas", "6 estrelas", "4 estrelas", "5 estrelas"], "As estrelas aumentam uma a cada vez: 1, 2, 3, 4 e depois 5 estrelas."],
  "TPR57_1_19": ["O que vem a seguir? Preto, branco, preto, branco, preto, ?", "Duas cores se alternam!", ["Cinza", "Branco", "Marrom", "Preto"], "Preto e branco se alternam. Depois de preto vem branco."],
  "TPR57_1_20": ["O que vem a seguir? Sim, Não, Sim, Não, Sim, ?", "Sim e Não alternativo.", ["Talvez", "Sim", "Não", "Às vezes"], "Sim e Não alternativo. Depois do Sim vem o Não."],

