  "TPR57_3_07": ["O que vem a seguir? Pequeno, médio, grande, pequeno, médio, grande, pequeno, médio, ?", "Três tamanhos se repetem do menor para o maior.", ["Pequeno", "Grande", "Médio", "Minúsculo"], "O padrão é pequeno, médio, grande repetindo. Depois de médio vem grande."],
  "TPR57_3_08": ["O que vem a seguir? Andar, correr, saltar, andar, correr, saltar, andar, correr, ?", "Três ações se repetem na mesma ordem.", ["Andar", "Passo", "Correr", "Saltar"], "O padrão é andar, correr, saltar repetindo. Depois de correr vem saltar."],
  "TPR57_3_09": ["Que dia vem depois do sábado?", "Pense nos dias da semana em ordem.", ["Domingo", "Segunda-feira", "Sexta-feira", "Terça-feira"], "Na semana: sexta, sábado, domingo. Depois do sábado vem o domingo."],
  "TPR57_3_10": ["O que vem a seguir? A, B, A, C, A, B, A, C, A, B, A, ?", "Encontre o grupo de repetição: A, B, A, C.", ["Um", "B", "c", "d"], "O padrão é A, B, A, C repetindo. Depois de A, B, A vem C."],
  "TPR57_3_11": ["O que vem a seguir? 1, 2, 3, 2, 1, 2, 3, 2, 1, 2, 3, ?", "Os números sobem e depois descem. Cuidado com o salto!", ["1", "2", "4", "3"], "O padrão é 1, 2, 3, 2 repetindo. Depois de 1, 2, 3 vem 2."],
  "TPR57_3_12": ["O que vem a seguir? Sol, Nuvem, Chuva, Sol, Nuvem, Chuva, Sol, Nuvem, ?", "Três palavras sobre o tempo são repetidas.", ["Sol", "Neve", "Nuvem", "Está chovendo"], "O padrão é Sol, Nuvem e Chuva repetindo. Depois da nuvem vem a chuva."],
  "TPR57_3_13": ["O que vem a seguir? Alto, mais alto, mais alto, alto, mais alto, mais alto, alto, mais alto, ?", "Três tamanhos são repetidos.", ["O mais alto", "Alto", "Superior", "Curto"], "O padrão é a repetição Alto, Mais Alto, Mais Alto. Depois do Mais Alto vem o Mais Alto."],
  "TPR57_3_14": ["Qual é o próximo número? 1, 3, 5, 1, 3, 5, 1, 3, ?", "Três números são repetidos.", ["1", "5", "3", "7"], "O padrão é 1, 3, 5 repetindo. Depois de 1, 3 vem 5."],
  "TPR57_3_15": ["O que vem a seguir? Comer, dormir, brincar, comer, dormir, brincar, comer, dormir, ?", "Três atividades são repetidas.", ["Coma", "dormir", "Jogue", "Descanse um pouco"], "O padrão é Comer, Dormir, Brincar que se repete. Depois do sono vem o jogo."],
  "TPR57_3_16": ["O que vem a seguir? Vermelho, Vermelho, Azul, Azul, Verde, Verde, Vermelho, Vermelho, Azul, Azul, ?", "Cada cor aparece duas vezes e a próxima cor começa.", ["Vermelho", "Azul", "Verde", "Amarelo"], "O padrão é vermelho, vermelho, azul, azul, verde, verde repetindo. Depois do Azul, o Azul segue o Verde."],
  "TPR57_3_17": ["Qual é o próximo número? Um, dois, três, quatro, cinco, seis, ?", "Continue contando!", ["Oito", "Sete", "Nove", "Dez"], "Contamos: um, dois, três, quatro, cinco, seis, sete."],
