  "TNR57_1_05": ["O que vem a seguir? 1, 3, 5, 7, ?", "Pulamos um número de cada vez: 1, pulamos 2, 3, pulamos 4, 5...", ["8", "10", "11", "9"], "Contamos por 2s (números ímpares): 1, 3, 5, 7, 9. O próximo número é 9."],
  "TNR57_1_06": ["O que vem a seguir? 4, 6, 8, 10, ?", "Conte de 2 a 2. Quanto é 10 mais 2?", ["12", "11", "14", "9"], "Contamos de 2 a 2: 4, 6, 8, 10, 12. O próximo número é 12."],
  "TNR57_1_07": ["O que vem a seguir? 6, 7, 8, 9, ?", "Continue contando! O que vem depois do 9?", ["11", "10", "12", "8"], "Contamos de 1 a 1: 6, 7, 8, 9, 10. O próximo número é 10."],
  "TNR57_1_08": ["O que vem a seguir? 2, 3, 4, 5, ?", "Conte de um a um.", ["7", "5", "6", "8"], "Contamos de 1 a 1: 2, 3, 4, 5, 6. O próximo número é 6."],
  "TNR57_1_09": ["O que vem a seguir? 7, 8, 9, 10, ?", "Qual número vem depois de 10?", ["12", "10", "9", "11"], "Contamos de 1 a 1: 7, 8, 9, 10, 11. O próximo número é 11."],
  "TNR57_1_10": ["O que vem a seguir? 6, 8, 10, 12, ?", "Saltamos de 2 para 2 todas as vezes!", ["14", "13", "15", "16"], "Contamos de 2 em 2: 6, 8, 10, 12, 14. O próximo número é 14."],
  "TNR57_1_11": ["O que vem a seguir? 10, 11, 12, 13, ?", "Continue contando de um a um!", ["15", "14", "12", "16"], "Contamos de 1 a 1: 10, 11, 12, 13, 14. O próximo número é 14."],
  "TNR57_1_12": ["Qual número está faltando? 1, 2, ?, 4, 5", "Qual número está entre 2 e 4?", ["6", "7", "3", "0"], "Contando 1, 2, 3, 4, 5. O número que falta é 3."],
  "TNR57_1_13": ["O que vem a seguir? 8, 9, 10, 11, ?", "Qual número vem depois de 11?", ["10", "13", "14", "12"], "Contamos de 1 a 1: 8, 9, 10, 11, 12. O próximo número é 12."],
